package com.xda.sa2ration.lut;
import com.xda.sa2ration.backend.CapabilityStatus;import org.junit.Test;import static org.junit.Assert.*;
public final class CompanionModuleDetectorTest {@Test public void parsesInstalledAdapterCapabilities(){CompanionModuleStatus status=CompanionModuleDetector.parse("module.installed=true\nmodule.version=1.0.0\nadapter.id=test-oled\ngamma=supported\nlut1d=experimental\nlut3d=unsupported\n");assertTrue(status.installed);assertTrue(status.hasAdapter());assertEquals(CapabilityStatus.SUPPORTED,status.gamma);assertEquals(CapabilityStatus.EXPERIMENTAL,status.lut1d);assertEquals(CapabilityStatus.UNSUPPORTED,status.lut3d);}@Test public void missingModuleRequiresModule(){CompanionModuleStatus status=CompanionModuleDetector.parse("");assertFalse(status.installed);assertEquals(CapabilityStatus.REQUIRES_MODULE,status.gamma);}}
